/* =========================
   HELPERS
   ========================= */
function makeSpec(spec) {
  return {
    ...BASE_CONFIG,
    ...spec,
    config: {
      ...BASE_CONFIG.config,
      ...(spec.config || {})
    }
  };
}

function showChartError(targetId, message) {
  const target = document.getElementById(targetId);
  if (!target) return;

  target.innerHTML = `
    <div class="error-box">
      <strong>Chart failed to render:</strong> ${targetId}<br>
      ${message}
    </div>
  `;
}

function renderChart(targetId, spec) {
  vegaEmbed(`#${targetId}`, spec, { actions: false, renderer: "svg" })
    .then(() => console.log(`${targetId} rendered successfully`))
    .catch((error) => {
      console.error(`Error rendering ${targetId}:`, error);
      showChartError(targetId, "Open the browser console to inspect the Vega-Lite error.");
    });
}

function setLastModified() {
  const target = document.getElementById("last-modified");
  if (!target) return;

  const modified = new Date(document.lastModified);
  target.textContent = modified.toLocaleDateString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric"
  });
}

async function loadCSV(path) {
  const response = await fetch(path);
  if (!response.ok) {
    throw new Error(`Failed to load CSV: ${path} (${response.status})`);
  }
  const text = await response.text();
  return vega.read(text, { type: "csv", parse: "auto" });
}

function computeRecoveryIndex(quarterly) {
  const base2019 = quarterly.filter((d) => d.year === 2019);
  const baseline =
    base2019.reduce((sum, d) => sum + d.arrivals, 0) / base2019.length;

  return quarterly.map((d) => ({
    ...d,
    recovery_index: (d.arrivals / baseline) * 100
  }));
}

function computeStateChangeRows(stateCore) {
  const wantedYears = [2015, 2022];
  return stateCore
    .filter((d) => wantedYears.includes(d.year))
    .map((d) => ({
      ...d,
      period: String(d.year)
    }));
}

function computeExpenditureShareChange(expenditure) {
  const years = [2000, 2020];
  const filtered = expenditure.filter((d) => years.includes(d.year));

  const totals = {};
  filtered.forEach((d) => {
    totals[d.year] = (totals[d.year] || 0) + d.expenditure_rm_million;
  });

  return filtered.map((d) => ({
    ...d,
    share: d.expenditure_rm_million / totals[d.year]
  }));
}

function renderMapChart(targetId, state2022) {
  try {
    const stateValues = state2022.map((d) => ({
      state: d.state,
      international_hotel_guests: +d.international_hotel_guests,
      occupancy_rate: +d.occupancy_rate
    }));

    console.log("Map state values:", stateValues);

    const mapSpec = {
      $schema: "https://vega.github.io/schema/vega-lite/v5.json",
      width: "container",
      height: 430,
      autosize: { type: "fit", contains: "padding", resize: true },
      background: null,
      config: {
        font: "Arial",
        view: { stroke: null }
      },
      projection: { type: "mercator" },
      layer: [
        {
          data: {
            values: MALAYSIA_TOPO,
            format: { type: "topojson", feature: "states" }
          },
          transform: [
            {
              calculate:
                "datum.properties.Name === 'Kuala Lumpur' ? 'W.P. Kuala Lumpur' : " +
                "datum.properties.Name === 'Labuan' ? 'W.P. Labuan' : " +
                "datum.properties.Name === 'Putrajaya' ? 'W.P. Putrajaya' : " +
                "datum.properties.Name === 'Penang' ? 'Pulau Pinang' : " +
                "datum.properties.Name",
              as: "state_match"
            },
            {
              lookup: "state_match",
              from: {
                data: { values: stateValues },
                key: "state",
                fields: ["international_hotel_guests", "occupancy_rate"]
              }
            },
            {
              filter: "isValid(datum.international_hotel_guests)"
            }
          ],
          mark: {
            type: "geoshape",
            stroke: "#ffffff",
            strokeWidth: 1.2
          },
          encoding: {
            color: {
              field: "international_hotel_guests",
              type: "quantitative",
              title: "International guests",
              scale: { scheme: "blues" },
              legend: {
                orient: "bottom",
                gradientLength: 220,
                titleFontSize: 12,
                labelFontSize: 11
              }
            },
            tooltip: [
              {
                field: "state_match",
                type: "nominal",
                title: "State"
              },
              {
                field: "international_hotel_guests",
                type: "quantitative",
                title: "International hotel guests",
                format: ","
              },
              {
                field: "occupancy_rate",
                type: "quantitative",
                title: "Occupancy rate (%)",
                format: ".1f"
              }
            ]
          }
        }
      ]
    };

    vegaEmbed(`#${targetId}`, mapSpec, {
      actions: false,
      renderer: "svg"
    })
      .then(() => console.log(`${targetId} rendered successfully (TopoJSON map)`))
      .catch((error) => {
        console.error(`Error rendering ${targetId}:`, error);
        showChartError(targetId, "Open the browser console to inspect the map error.");
      });

  } catch (error) {
    console.error(`Map preparation failed for ${targetId}:`, error);
    showChartError(targetId, "Map preparation failed. Open the browser console for details.");
  }
}

